INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("春咲 ひより", 0, 0, 2, 1, 1001, 1, 0, "お！\nあそこに困ってそうな人発見！", 1, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("草野 優衣", 0, 0, 2, 1, 1002, 1, 0, "大切な人を\n守れるようになりたい…って", 1, 0, "みんなみたいに\nわたしも強くならなきゃ", "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("士条 怜", 0, 0, 2, 1, 1003, 1, 0, "キミに必要な集中力と感性が", 1, 0, "フェンシングを始めてみては？", "少しは磨かれると思いますよ。", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("穂高 みそぎ", 0, 0, 2, 1, 1004, 1, 0, "今日はなにして遊ぶ？", 1, 0, "ねぇ、にいちゃん！", "みそぎはねぇ、\nかくれんぼやりたい！", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("風宮 あかり", 0, 0, 2, 1, 1006, 1, 0, "ねぇ…", 1, 0, "風宮あかりです", "私といっしょに…\nいかない？", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("出雲 宮子", 0, 0, 2, 1, 1007, 1, 0, "プリンたべたいのー", 1, 0, "出雲宮子なのー", "食べ物の恨みは怖いのー", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("虹村 雪", 0, 0, 2, 1, 1008, 1, 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 1, 0, "ボクは虹村雪。", "いいよ。\n見られることは運命さ…", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("柊杏奈", 0, 0, 2, 1, 1009, 1, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, 0, "フッ…聞いて後悔するがいい！", "人呼んで「疾風の冥姫」!!", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("姫宮 真歩", 0, 0, 2, 1, 1010, 1, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, 0, "マホマホ王国のプリンセス、\nまほ姫どす", "ほんまおおきにやわ～♪", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("衣之咲 璃乃", 0, 0, 2, 1, 1011, 1, 0, "生き別れたお兄ちゃんを探して\n三千世界！", 1, 0, "衣之咲璃乃です！", "ここで会ったが\n100年目～！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("柏崎 初音", 0, 0, 2, 1, 1012, 1, 0, "ち、超能力って…\n何のことかな～？", 1, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", "…って、お願い！\n誰にも言わないでおいて～！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("美波 鈴奈", 0, 0, 2, 1, 1016, 1, 0, "一応カリスマ読モJKやってまっす！", 1, 0, "ちょす！\n美波鈴奈だよ～♪", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("喜屋武 香織", 0, 0, 2, 1, 1017, 1, 0, "東京は遊園地みたいなところさー", 1, 0, "はいたーい。\n喜屋武香織さー。", "でも、沖縄もとってもいいとこさー", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("支倉 伊緒", 0, 0, 2, 1, 1018, 1, 0, "先生って呼ばれるのは\nくすぐったいから", 1, 0, "支倉伊緒です。", "イオちゃんって呼んでね。", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("茜 ミミ", 0, 0, 2, 1, 1020, 1, 0, "あ！/\お兄ちゃ～ん\nまってよ～", 1, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", "ミミをおいてかないでぇ～", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("栗林 くるみ", 0, 0, 2, 1, 1021, 1, 0, "あの……\nふぇ……", 1, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", "ふぇぇぇぇぇん……", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("風宮 より", 0, 0, 2, 1, 1022, 1, 0, "こんな私に貴重な時間を\n割いていただき、", 1, 0, "風宮よりです。\nあああああ！", "なんてありがとうございます！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("北条 綾音", 0, 0, 2, 1, 1023, 1, 0, "おにいちゃんどこいくの？\nえ？", 1, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", "私こっち行きたいー\nね、早く早くー", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("天野 すずめ", 0, 0, 2, 1, 1025, 1, 0, "ふ、不束者ですが\nどうぞ末永く…って、", 1, 0, "わっ…わっ…私、\n天野すずめといいます！", "これて何か違う…\nあああすみません！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("倉石 恵理子", 0, 0, 2, 1, 1027, 1, 0, "あなたは…運命の……\n伴侶……", 1, 0, "……クスクス…私は\n…倉石恵理子……", "離しませんわ………\n絶対に…!!", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("佐々木 咲恋", 0, 0, 2, 1, 1028, 1, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", "…そうでしょ？？", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("桜井 望", 0, 0, 2, 1, 1029, 1, 0, "ぇっと…\nキミ、私のこと知らないの?!", 1, 0, "桜井望だよ！\nよろしくねっ", "あはは、\n私もまだまだだなぁ～", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ニノン・ジュベール", 0, 0, 2, 1, 1030, 1, 0, "初めまして、\n私はニノン・ジュベール申すデス！", 1, 0, "デケデケデンっ！", "ショーグン、\nワタシと一緒に天下統一デース！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("上喜 しのぶ", 0, 0, 2, 1, 1031, 1, 0, "でもって私の隣にいるのが……\nえ、見えない？", 1, 0, "上喜しのぶです。\n手元のドクロが父です。", "おかしいですね……", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("野戸まひる", 0, 0, 2, 1, 1033, 1, 0, "けんども\nそれには足りないモンが…", 1, 0, "目指すはビッグな\nお笑い芸人だっぺ！", "そう、\nオラのボケに突っ込める相方が…！", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("綾瀬 ゆかり", 0, 0, 2, 1, 1034, 1, 0, "ちょっと緊張しちゃって…", 1, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", "ちょ\nちょっと一杯飲んできます…！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("氷川 鏡華", 0, 0, 2, 1, 1036, 1, 0, "知らない人とは話しちゃいけないので", 1, 0, "氷川鏡華…です", "これ以上お話しすることは…\nないです！", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("柏崎 栞", 0, 0, 2, 1, 1038, 1, 0, "……あ、アラーム。", 1, 0, "柏崎…栞です。", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("双葉 碧", 0, 0, 2, 1, 1040, 1, 0, "私、一人も友達がいなくて……", 1, 0, "ふ、双葉碧です。", "野に咲く花が、\n唯一の話相手です。", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("三角 千歌", 0, 0, 2, 1, 1042, 1, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, 0, "三角千歌です。", "そう思っています。", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("安芸 真琴", 0, 0, 2, 1, 1043, 1, 0, "あぁ？\nお前のそいつの仲間か？", 1, 0, "安芸真琴だ。", "う、疑ってすまなかったな…", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("イリヤ・オーンスタイン", 0, 0, 2, 1, 1044, 1, 0, "生けとし生ける全ての者よ！", 1, 0, "わらわこそは夜を総べる者！", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("遠見 空花", 0, 0, 2, 1, 1045, 1, 0, "ぐふふふふ……はっ！", 1, 0, "そこで騎士は妖精を乱暴に……", "ｌク、クウカに何かご用ですか!?", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("宮坂たまき", 0, 0, 2, 1, 1046, 1, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", "う～ん…\n猫ってホントに最高にゃ～♪", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("大神 美冬", 0, 0, 2, 1, 1048, 1, 0, "それでは早速クエストに…", 1, 0, "大神美冬よ！", "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("星野静流", 0, 0, 2, 1, 1049, 1, 0, "クエストもバトルも\n掃除も洗濯も", 1, 0, "星野静流だよ！", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("玉泉美咲", 0, 0, 2, 1, 1050, 1, 0, "見ての通りの\nセクシー美少女で", 1, 0, "アタシは玉泉美咲。", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("リマ", 0, 0, 2, 1, 1052, 1, 0, "？？？？", 1, 0, "？？？", "？？？？", 0, 1.4);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("モニカ・ヴァイスヴィント", 0, 0, 2, 1, 1053, 1, 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, "モニカ・ヴァイスヴィントだ。", "そ、そこまでいうなら\nもらってやる", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("ペコリーヌ", 0, 0, 2, 1, 1058, 1, 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, "モニカ・ヴァイスヴィントだ。", "そ、そこまでいうなら\nもらってやる", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("コッコロ", 0, 0, 2, 1, 1059, 1, 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, "モニカ・ヴァイスヴィントだ。", "そ、そこまでいうなら\nもらってやる", 0, 1.5);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES ("キャル", 0, 0, 2, 1, 1060, 1, 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, "モニカ・ヴァイスヴィントだ。", "そ、そこまでいうなら\nもらってやる", 0, 1.5);
